solution_code:
#include <iostream>

void safePrint(int* p) {
    if (p != nullptr) {
        std::cout << *p << '\n';
    } else {
        std::cout << "null\n";
    }
}

int main() {
    int flag;
    std::cin >> flag;
    if (flag == 1) {
        int value;
        std::cin >> value;
        safePrint(&value);
    } else {
        safePrint(nullptr);
    }
    return 0;
}

