solution_code:
#include <iostream>

int* firstPositive(int& a, int& b, int& c) {
    if (a > 0) return &a;
    if (b > 0) return &b;
    if (c > 0) return &c;
    return nullptr;
}

int main() {
    int a, b, c;
    std::cin >> a >> b >> c;
    int* result = firstPositive(a, b, c);
    if (result != nullptr) {
        std::cout << *result << '\n';
    } else {
        std::cout << "none\n";
    }
    return 0;
}
